mapper.insert:
INSERT INTO pki_revocation.revocation_current (
    cert_serial, issuer_id, revoked_at, reason, first_activated_at, updated_at
) VALUES (
    #{certSerial}, #{issuerId}, #{revokedAt}, #{reason}, #{firstActivatedAt}, #{updatedAt}
)

mapper.select:
SELECT cert_serial, issuer_id, revoked_at, reason, first_activated_at, updated_at
FROM pki_revocation.revocation_current
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}

mapper.delete:
DELETE FROM pki_revocation.revocation_current
WHERE cert_serial = #{certSerial}
  AND issuer_id = #{issuerId}
